    public Object nonce()
    {
        return Helpers.subtract(this.milliseconds(), Helpers.GetValue(this.options, "timeDifference"));
    }

    /**
     * @method
     * @name tokocrypto#fetchTime
     * @see https://www.tokocrypto.com/apidocs/#check-server-time
     * @description fetches the current integer timestamp in milliseconds from the exchange server
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {int} the current integer timestamp in milliseconds from the exchange server
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTime(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object response = (this.publicGetOpenV1CommonTime(parameters)).join();
            //
            // {
            //     "code": 0,
            //     "msg": "Success",
            //     "data": null,
            //     "timestamp": 1737378074159
            // }
            //
            return this.safeInteger(response, "timestamp");
        });

    }

    /**
     * @method
     * @name tokocrypto#fetchMarkets
     * @see https://www.tokocrypto.com/apidocs/#get-all-supported-trading-symbol
     * @description retrieves data on all markets for tokocrypto
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object[]} an array of objects representing market data
     */
    public java.util.concurrent.CompletableFuture<Object> fetchMarkets(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            Object response = (this.publicGetOpenV1CommonSymbols(parameters)).join();
            //
            //     {
            //         "code":0,
            //         "msg":"Success",
            //         "data":{
            //             "list":[
            //                 {
            //                     "type":1,
            //                     "symbol":"1INCH_BTC",
            //                     "baseAsset":"1INCH",
            //                     "basePrecision":8,
            //                     "quoteAsset":"BTC",
            //                     "quotePrecision":8,
            //                     "filters":[
            //                         {"filterType":"PRICE_FILTER","minPrice":"0.00000001","maxPrice":"1000.00000000","tickSize":"0.00000001","applyToMarket":false},
            //                         {"filterType":"PERCENT_PRICE","multiplierUp":5,"multiplierDown":0.2,"avgPriceMins":"5","applyToMarket":false},
            //                         {"filterType":"LOT_SIZE","minQty":"0.10000000","maxQty":"90000000.00000000","stepSize":"0.10000000","applyToMarket":false},
            //                         {"filterType":"MIN_NOTIONAL","avgPriceMins":"5","minNotional":"0.00010000","applyToMarket":true},
            //                         {"filterType":"ICEBERG_PARTS","applyToMarket":false,"limit":"10"},
            //                         {"filterType":"MARKET_LOT_SIZE","minQty":"0.00000000","maxQty":"79460.14117231","stepSize":"0.00000000","applyToMarket":false},
            //                         {"filterType":"TRAILING_DELTA","applyToMarket":false},
            //                         {"filterType":"MAX_NUM_ORDERS","applyToMarket":false},
            //                         {"filterType":"MAX_NUM_ALGO_ORDERS","applyToMarket":false,"maxNumAlgoOrders":"5"}
            //                     ],
            //                     "orderTypes":["LIMIT","LIMIT_MAKER","MARKET","STOP_LOSS_LIMIT","TAKE_PROFIT_LIMIT"],
            //                     "icebergEnable":1,
            //                     "ocoEnable":1,
            //                     "spotTradingEnable":1,
            //                     "marginTradingEnable":1,
            //                     "permissions":["SPOT","MARGIN"]
            //                 },
            //             ]
            //         },
            //         "timestamp":1659492212507
            //     }
            //
            if (Helpers.isTrue(Helpers.GetValue(this.options, "adjustForTimeDifference")))
            {
                (this.loadTimeDifference()).join();
            }
            Object data = this.safeValue(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object list = this.safeValue(data, "list", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
            Object result = new java.util.ArrayList<Object>(java.util.Arrays.asList());
            for (var i = 0; Helpers.isLessThan(i, Helpers.getArrayLength(list)); i++)
            {
                Object market = Helpers.GetValue(list, i);
                Object baseId = this.safeString(market, "baseAsset");
                Object quoteId = this.safeString(market, "quoteAsset");
                Object id = this.safeString(market, "symbol");
                Object lowercaseId = this.safeStringLower(market, "symbol");
                Object settleId = this.safeString(market, "marginAsset");
                Object base = this.safeCurrencyCode(baseId);
                Object quote = this.safeCurrencyCode(quoteId);
                Object settle = this.safeCurrencyCode(settleId);
                Object symbol = Helpers.add(Helpers.add(base, "/"), quote);
                Object filters = this.safeValue(market, "filters", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                Object filtersByType = this.indexBy(filters, "filterType");
                Object status = this.safeString(market, "spotTradingEnable");
                Object active = (Helpers.isEqual(status, "1"));
                Object permissions = this.safeValue(market, "permissions", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                for (var j = 0; Helpers.isLessThan(j, Helpers.getArrayLength(permissions)); j++)
                {
                    if (Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(permissions, j), "TRD_GRP_003")))
                    {
                        active = false;
                        break;
                    }
                }
                Object isMarginTradingAllowed = this.safeBool(market, "isMarginTradingAllowed", false);
                final Object finalBase = base;
                final Object finalActive = active;
                Object entry = new java.util.HashMap<String, Object>() {{
                    put( "id", id );
                    put( "lowercaseId", lowercaseId );
                    put( "symbol", symbol );
                    put( "base", finalBase );
                    put( "quote", quote );
                    put( "settle", settle );
                    put( "baseId", baseId );
                    put( "quoteId", quoteId );
                    put( "settleId", settleId );
                    put( "type", "spot" );
                    put( "spot", true );
                    put( "margin", isMarginTradingAllowed );
                    put( "swap", false );
                    put( "future", false );
                    put( "delivery", false );
                    put( "option", false );
                    put( "active", finalActive );
                    put( "contract", false );
                    put( "linear", null );
                    put( "inverse", null );
                    put( "contractSize", null );
                    put( "expiry", null );
                    put( "expiryDatetime", null );
                    put( "strike", null );
                    put( "optionType", null );
                    put( "precision", new java.util.HashMap<String, Object>() {{
                        put( "amount", TokocryptoCore.this.parseNumber(TokocryptoCore.this.parsePrecision(TokocryptoCore.this.safeString(market, "quantityPrecision"))) );
                        put( "price", TokocryptoCore.this.parseNumber(TokocryptoCore.this.parsePrecision(TokocryptoCore.this.safeString(market, "pricePrecision"))) );
                        put( "base", TokocryptoCore.this.parseNumber(TokocryptoCore.this.parsePrecision(TokocryptoCore.this.safeString(market, "baseAssetPrecision"))) );
                        put( "quote", TokocryptoCore.this.parseNumber(TokocryptoCore.this.parsePrecision(TokocryptoCore.this.safeString(market, "quotePrecision"))) );
                    }} );
                    put( "limits", new java.util.HashMap<String, Object>() {{
                        put( "leverage", new java.util.HashMap<String, Object>() {{
                            put( "min", null );
                            put( "max", null );
                        }} );
                        put( "amount", new java.util.HashMap<String, Object>() {{
                            put( "min", null );
                            put( "max", null );
                        }} );
                        put( "price", new java.util.HashMap<String, Object>() {{
                            put( "min", null );
                            put( "max", null );
                        }} );
                        put( "cost", new java.util.HashMap<String, Object>() {{
                            put( "min", null );
                            put( "max", null );
                        }} );
                    }} );
                    put( "created", null );
                    put( "info", market );
                }};
                if (Helpers.isTrue(Helpers.inOp(filtersByType, "PRICE_FILTER")))
                {
                    Object filter = this.safeValue(filtersByType, "PRICE_FILTER", new java.util.HashMap<String, Object>() {{}});
                    Helpers.addElementToObject(Helpers.GetValue(entry, "precision"), "price", this.safeNumber(filter, "tickSize"));
                    // PRICE_FILTER reports zero values for maxPrice
                    // since they updated filter types in November 2018
                    // https://github.com/ccxt/ccxt/issues/4286
                    // therefore limits['price']['max'] doesn't have any meaningful value except undefined
                    Helpers.addElementToObject(Helpers.GetValue(entry, "limits"), "price", new java.util.HashMap<String, Object>() {{
        put( "min", TokocryptoCore.this.safeNumber(filter, "minPrice") );
        put( "max", TokocryptoCore.this.safeNumber(filter, "maxPrice") );
    }});
                    Helpers.addElementToObject(Helpers.GetValue(entry, "precision"), "price", Helpers.GetValue(filter, "tickSize"));
                }
                if (Helpers.isTrue(Helpers.inOp(filtersByType, "LOT_SIZE")))
                {
                    Object filter = this.safeValue(filtersByType, "LOT_SIZE", new java.util.HashMap<String, Object>() {{}});
                    Helpers.addElementToObject(Helpers.GetValue(entry, "precision"), "amount", this.safeNumber(filter, "stepSize"));
                    Helpers.addElementToObject(Helpers.GetValue(entry, "limits"), "amount", new java.util.HashMap<String, Object>() {{
        put( "min", TokocryptoCore.this.safeNumber(filter, "minQty") );
        put( "max", TokocryptoCore.this.safeNumber(filter, "maxQty") );
    }});
                }
                if (Helpers.isTrue(Helpers.inOp(filtersByType, "MARKET_LOT_SIZE")))
                {
                    Object filter = this.safeValue(filtersByType, "MARKET_LOT_SIZE", new java.util.HashMap<String, Object>() {{}});
                    Helpers.addElementToObject(Helpers.GetValue(entry, "limits"), "market", new java.util.HashMap<String, Object>() {{
        put( "min", TokocryptoCore.this.safeNumber(filter, "minQty") );
        put( "max", TokocryptoCore.this.safeNumber(filter, "maxQty") );
    }});
                }
                if (Helpers.isTrue(Helpers.inOp(filtersByType, "MIN_NOTIONAL")))
                {
                    Object filter = this.safeValue(filtersByType, "MIN_NOTIONAL", new java.util.HashMap<String, Object>() {{}});
                    Helpers.addElementToObject(Helpers.GetValue(Helpers.GetValue(entry, "limits"), "cost"), "min", this.safeNumber2(filter, "minNotional", "notional"));
                }
                ((java.util.List<Object>)result).add(entry);
            }
            return result;
        });

    }

    /**
     * @method
     * @name tokocrypto#fetchOrderBook
     * @see https://www.tokocrypto.com/apidocs/#order-book
     * @description fetches information on open orders with bid (buy) and ask (sell) prices, volumes and other data
     * @param {string} symbol unified symbol of the market to fetch the order book for
     * @param {int} [limit] the maximum amount of order book entries to return
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} A dictionary of [order book structures]{@link https://docs.ccxt.com/?id=order-book-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchOrderBook(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object limit = Helpers.getArg(optionalArgs, 0, null);
            Object parameters = Helpers.getArg(optionalArgs, 1, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{}};
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", limit); // default 100, max 5000, see https://github.com/binance/binance-spot-api-docs/blob/master/rest-api.md#order-book
            }
            Object response = null;
            if (Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(market, "quote"), "USDT")))
            {
                Helpers.addElementToObject(request, "symbol", Helpers.add(this.safeString(market, "baseId", ""), this.safeString(market, "quoteId", "")));
                response = (this.binanceGetDepth(this.extend(request, parameters))).join();
            } else
            {
                Helpers.addElementToObject(request, "symbol", Helpers.GetValue(market, "id"));
                response = (this.publicGetOpenV1MarketDepth(this.extend(request, parameters))).join();
            }
            //
            // future
            //
            //     {
            //         "lastUpdateId":333598053905,
            //         "E":1618631511986,
            //         "T":1618631511964,
            //         "bids":[
            //             ["2493.56","20.189"],
            //             ["2493.54","1.000"],
            //             ["2493.51","0.005"]
            //         ],
            //         "asks":[
            //             ["2493.57","0.877"],
            //             ["2493.62","0.063"],
            //             ["2493.71","12.054"],
            //         ]
            //     }
            // type not 1
            //     {
            //         "code":0,
            //         "msg":"Success",
            //         "data":{
            //            "lastUpdateId":3204783,
            //            "bids":[],
            //            "asks": []
            //         },
            //         "timestamp":1692262634599
            //     }
            Object data = this.safeValue(response, "data", response);
            Object timestamp = this.safeInteger2(response, "T", "timestamp");
            Object orderbook = this.parseOrderBook(data, symbol, timestamp);
            Helpers.addElementToObject(orderbook, "nonce", this.safeInteger(data, "lastUpdateId"));
            return orderbook;
        });

    }

    public Object parseTrade(Object trade, Object... optionalArgs)
    {
        //
        // aggregate trades
        // https://github.com/binance-exchange/binance-official-api-docs/blob/master/rest-api.md#compressedaggregate-trades-list
        //
        //     {
        //         "a": 26129,         // Aggregate tradeId
        //         "p": "0.01633102",  // Price
        //         "q": "4.70443515",  // Quantity
        //         "f": 27781,         // First tradeId
        //         "l": 27781,         // Last tradeId
        //         "T": 1498793709153, // Timestamp
        //         "m": true,          // Was the buyer the maker?
        //         "M": true           // Was the trade the best price match?
        //     }
        //
        // recent public trades and old public trades
        // https://github.com/binance-exchange/binance-official-api-docs/blob/master/rest-api.md#recent-trades-list
        // https://github.com/binance-exchange/binance-official-api-docs/blob/master/rest-api.md#old-trade-lookup-market_data
        //
        //     {
        //         "id": 28457,
        //         "price": "4.00000100",
        //         "qty": "12.00000000",
        //         "time": 1499865549590,
        //         "isBuyerMaker": true,
        //         "isBestMatch": true
        //     }
        //
        // private trades
        // https://github.com/binance-exchange/binance-official-api-docs/blob/master/rest-api.md#account-trade-list-user_data
        //
        //     {
        //         "symbol": "BNBBTC",
        //         "id": 28457,
        //         "orderId": 100234,
        //         "price": "4.00000100",
        //         "qty": "12.00000000",
        //         "commission": "10.10000000",
        //         "commissionAsset": "BNB",
        //         "time": 1499865549590,
        //         "isBuyer": true,
        //         "isMaker": false,
        //         "isBestMatch": true
        //     }
        //
        // futures trades
        // https://binance-docs.github.io/apidocs/futures/en/#account-trade-list-user_data
        //
        //     {
        //       "accountId": 20,
        //       "buyer": False,
        //       "commission": "-0.07819010",
        //       "commissionAsset": "USDT",
        //       "counterPartyId": 653,
        //       "id": 698759,
        //       "maker": False,
        //       "orderId": 25851813,
        //       "price": "7819.01",
        //       "qty": "0.002",
        //       "quoteQty": "0.01563",
        //       "realizedPnl": "-0.91539999",
        //       "side": "SELL",
        //       "symbol": "BTCUSDT",
        //       "time": 1569514978020
        //     }
        //     {
        //       "symbol": "BTCUSDT",
        //       "id": 477128891,
        //       "orderId": 13809777875,
        //       "side": "SELL",
        //       "price": "38479.55",
        //       "qty": "0.001",
        //       "realizedPnl": "-0.00009534",
        //       "marginAsset": "USDT",
        //       "quoteQty": "38.47955",
        //       "commission": "-0.00076959",
        //       "commissionAsset": "USDT",
        //       "time": 1612733566708,
        //       "positionSide": "BOTH",
        //       "maker": true,
        //       "buyer": false
        //     }
        //
        // { respType: FULL }
        //
        //     {
        //       "price": "4000.00000000",
        //       "qty": "1.00000000",
        //       "commission": "4.00000000",
        //       "commissionAsset": "USDT",
        //       "tradeId": "1234",
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger2(trade, "T", "time");
        Object price = this.safeString2(trade, "p", "price");
        Object amount = this.safeString2(trade, "q", "qty");
        Object cost = this.safeString2(trade, "quoteQty", "baseQty"); // inverse futures
        Object marketId = this.safeString(trade, "symbol");
        Object symbol = this.safeSymbol(marketId, market);
        Object id = this.safeString2(trade, "t", "a");
        id = this.safeString2(trade, "id", "tradeId", id);
        Object side = null;
        Object orderId = this.safeString(trade, "orderId");
        Object buyerMaker = this.safeValue2(trade, "m", "isBuyerMaker");
        Object takerOrMaker = null;
        if (Helpers.isTrue(!Helpers.isEqual(buyerMaker, null)))
        {
            side = ((Helpers.isTrue(buyerMaker))) ? "sell" : "buy"; // this is reversed intentionally
            takerOrMaker = "taker";
        } else if (Helpers.isTrue(Helpers.inOp(trade, "side")))
        {
            side = this.safeStringLower(trade, "side");
        } else
        {
            if (Helpers.isTrue(Helpers.inOp(trade, "isBuyer")))
            {
                side = ((Helpers.isTrue(Helpers.GetValue(trade, "isBuyer")))) ? "buy" : "sell"; // this is a true side
            }
        }
        Object fee = null;
        if (Helpers.isTrue(Helpers.inOp(trade, "commission")))
        {
            fee = new java.util.HashMap<String, Object>() {{
                put( "cost", TokocryptoCore.this.safeString(trade, "commission") );
                put( "currency", TokocryptoCore.this.safeCurrencyCode(TokocryptoCore.this.safeString(trade, "commissionAsset")) );
            }};
        }
        if (Helpers.isTrue(Helpers.inOp(trade, "isMaker")))
        {
            takerOrMaker = ((Helpers.isTrue(Helpers.GetValue(trade, "isMaker")))) ? "maker" : "taker";
        }
        if (Helpers.isTrue(Helpers.inOp(trade, "maker")))
        {
            takerOrMaker = ((Helpers.isTrue(Helpers.GetValue(trade, "maker")))) ? "maker" : "taker";
        }
        final Object finalId = id;
        final Object finalSide = side;
        final Object finalTakerOrMaker = takerOrMaker;
        final Object finalFee = fee;
        return this.safeTrade(new java.util.HashMap<String, Object>() {{
            put( "info", trade );
            put( "timestamp", timestamp );
            put( "datetime", TokocryptoCore.this.iso8601(timestamp) );
            put( "symbol", symbol );
            put( "id", finalId );
            put( "order", orderId );
            put( "type", null );
            put( "side", finalSide );
            put( "takerOrMaker", finalTakerOrMaker );
            put( "price", price );
            put( "amount", amount );
            put( "cost", cost );
            put( "fee", finalFee );
        }}, market);
    }

    /**
     * @method
     * @name tokocrypto#fetchTrades
     * @see https://www.tokocrypto.com/apidocs/#recent-trades-list
     * @see https://www.tokocrypto.com/apidocs/#compressedaggregate-trades-list
     * @description get the list of most recent trades for a particular symbol
     * @param {string} symbol unified symbol of the market to fetch trades for
     * @param {int} [since] timestamp in ms of the earliest trade to fetch
     * @param {int} [limit] the maximum amount of trades to fetch
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {Trade[]} a list of [trade structures]{@link https://docs.ccxt.com/?id=public-trades}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchTrades(Object symbol, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object since = Helpers.getArg(optionalArgs, 0, null);
            Object limit = Helpers.getArg(optionalArgs, 1, null);
            Object parameters = Helpers.getArg(optionalArgs, 2, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object market = this.market(symbol);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "symbol", TokocryptoCore.this.getMarketIdByType(market) );
            }};
            if (Helpers.isTrue(!Helpers.isEqual(Helpers.GetValue(market, "quote"), "USDT")))
            {
                if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
                {
                    Helpers.addElementToObject(request, "limit", limit);
                }
                Object responseInner = this.publicGetOpenV1MarketTrades(this.extend(request, parameters));
                //
                //    {
                //       "code": 0,
                //       "msg": "success",
                //       "data": {
                //           "list": [
                //                {
                //                    "id": 28457,
                //                    "price": "4.00000100",
                //                    "qty": "12.00000000",
                //                    "time": 1499865549590,
                //                    "isBuyerMaker": true,
                //                    "isBestMatch": true
                //                }
                //            ]
                //        },
                //        "timestamp": 1571921637091
                //    }
                //
                Object data = this.safeDict(responseInner, "data", new java.util.HashMap<String, Object>() {{}});
                Object list = this.safeList(data, "list", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
                return this.parseTrades(list, market, since, limit);
            }
            if (Helpers.isTrue(!Helpers.isEqual(limit, null)))
            {
                Helpers.addElementToObject(request, "limit", limit); // default = 500, maximum = 1000
            }
            Object defaultMethod = "binanceGetTrades";
            Object method = this.safeString(this.options, "fetchTradesMethod", defaultMethod);
            Object response = null;
            if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(method, "binanceGetAggTrades"))) && Helpers.isTrue((!Helpers.isEqual(since, null)))))
            {
                Helpers.addElementToObject(request, "startTime", since);
                // https://github.com/ccxt/ccxt/issues/6400
                // https://github.com/binance-exchange/binance-official-api-docs/blob/master/rest-api.md#compressedaggregate-trades-list
                Helpers.addElementToObject(request, "endTime", this.sum(since, 3600000));
                response = (this.binanceGetAggTrades(this.extend(request, parameters))).join();
            } else
            {
                response = (this.binanceGetTrades(this.extend(request, parameters))).join();
            }
            //
            // Caveats:
            // - default limit (500) applies only if no other parameters set, trades up
            //   to the maximum limit may be returned to satisfy other parameters
            // - if both limit and time window is set and time window contains more
            //   trades than the limit then the last trades from the window are returned
            // - 'tradeId' accepted and returned by this method is "aggregate" trade id
            //   which is different from actual trade id
            // - setting both fromId and time window results in error
            //
            // aggregate trades
            //
            //     [
            //         {
            //             "a": 26129,         // Aggregate tradeId
            //             "p": "0.01633102",  // Price
            //             "q": "4.70443515",  // Quantity
            //             "f": 27781,         // First tradeId
            //             "l": 27781,         // Last tradeId
            //             "T": 1498793709153, // Timestamp
            //             "m": true,          // Was the buyer the maker?
            //             "M": true           // Was the trade the best price match?
            //         }
            //     ]
            //
            // recent public trades and historical public trades
            //
            //     [
            //         {
            //             "id": 28457,
            //             "price": "4.00000100",
            //             "qty": "12.00000000",
            //             "time": 1499865549590,
            //             "isBuyerMaker": true,
            //             "isBestMatch": true
            //         }
            //     ]
            //
            return this.parseTrades(response, market, since, limit);
        });

    }

    public Object parseTicker(Object ticker, Object... optionalArgs)
    {
        //
        //     {
        //         "symbol": "ETHBTC",
        //         "priceChange": "0.00068700",
        //         "priceChangePercent": "2.075",
        //         "weightedAvgPrice": "0.03342681",
        //         "prevClosePrice": "0.03310300",
        //         "lastPrice": "0.03378900",
        //         "lastQty": "0.07700000",
        //         "bidPrice": "0.03378900",
        //         "bidQty": "7.16800000",
        //         "askPrice": "0.03379000",
        //         "askQty": "24.00000000",
        //         "openPrice": "0.03310200",
        //         "highPrice": "0.03388900",
        //         "lowPrice": "0.03306900",
        //         "volume": "205478.41000000",
        //         "quoteVolume": "6868.48826294",
        //         "openTime": 1601469986932,
        //         "closeTime": 1601556386932,
        //         "firstId": 196098772,
        //         "lastId": 196186315,
        //         "count": 87544
        //     }
        //
        // coinm
        //     {
        //         "baseVolume": "214549.95171161",
        //         "closeTime": "1621965286847",
        //         "count": "1283779",
        //         "firstId": "152560106",
        //         "highPrice": "39938.3",
        //         "lastId": "153843955",
        //         "lastPrice": "37993.4",
        //         "lastQty": "1",
        //         "lowPrice": "36457.2",
        //         "openPrice": "37783.4",
        //         "openTime": "1621878840000",
        //         "pair": "BTCUSD",
        //         "priceChange": "210.0",
        //         "priceChangePercent": "0.556",
        //         "symbol": "BTCUSD_PERP",
        //         "volume": "81990451",
        //         "weightedAvgPrice": "38215.08713747"
        //     }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object timestamp = this.safeInteger(ticker, "closeTime");
        Object marketId = this.safeString(ticker, "symbol");
        Object symbol = this.safeSymbol(marketId, market);
        Object last = this.safeString(ticker, "lastPrice");
        Object isCoinm = (Helpers.inOp(ticker, "baseVolume"));
        Object baseVolume = null;
        Object quoteVolume = null;
        if (Helpers.isTrue(isCoinm))
        {
            baseVolume = this.safeString(ticker, "baseVolume");
            quoteVolume = this.safeString(ticker, "volume");
        } else
        {
            baseVolume = this.safeString(ticker, "volume");
            quoteVolume = this.safeString(ticker, "quoteVolume");
        }
        final Object finalBaseVolume = baseVolume;
        final Object finalQuoteVolume = quoteVolume;
        return this.safeTicker(new java.util.HashMap<String, Object>() {{
            put( "symbol", symbol );
            put( "timestamp", timestamp );
            put( "datetime", TokocryptoCore.this.iso8601(timestamp) );
            put( "high", TokocryptoCore.this.safeString(ticker, "highPrice") );
            put( "low", TokocryptoCore.this.safeString(ticker, "lowPrice") );
            put( "bid", TokocryptoCore.this.safeString(ticker, "bidPrice") );
            put( "bidVolume", TokocryptoCore.this.safeString(ticker, "bidQty") );
            put( "ask", TokocryptoCore.this.safeString(ticker, "askPrice") );
            put( "askVolume", TokocryptoCore.this.safeString(ticker, "askQty") );
            put( "vwap", TokocryptoCore.this.safeString(ticker, "weightedAvgPrice") );
            put( "open", TokocryptoCore.this.safeString(ticker, "openPrice") );
            put( "close", last );
            put( "last", last );
            put( "previousClose", TokocryptoCore.this.safeString(ticker, "prevClosePrice") );
            put( "change", TokocryptoCore.this.safeString(ticker, "priceChange") );
            put( "percentage", TokocryptoCore.this.safeString(ticker, "priceChangePercent") );
            put( "average", null );
            put( "baseVolume", finalBaseVolume );
            put( "quoteVolume", finalQuoteVolume );
            put( "info", ticker );
        }}, market);
    }

