    /**
     * @method
     * @name tokocrypto#fetchDepositAddress
     * @description fetch the deposit address for a currency associated with this account
     * @see https://www.tokocrypto.com/apidocs/#deposit-address-signed
     * @param {string} code unified currency code
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @returns {object} an [address structure]{@link https://docs.ccxt.com/?id=address-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> fetchDepositAddress(Object code, Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object parameters = Helpers.getArg(optionalArgs, 0, new java.util.HashMap<String, Object>() {{}});
            if (Helpers.isTrue(Helpers.isEqual(this.markets, null)))
            {
                (this.loadMarkets()).join();
            }
            Object currency = this.currency(code);
            Object request = new java.util.HashMap<String, Object>() {{
                put( "asset", Helpers.GetValue(currency, "id") );
            }};
            Object networks = this.safeValue(this.options, "networks", new java.util.HashMap<String, Object>() {{}});
            Object network = this.safeStringUpper(parameters, "network"); // this line allows the user to specify either ERC20 or ETH
            network = this.safeString(networks, network, network); // handle ERC20>ETH alias
            if (Helpers.isTrue(!Helpers.isEqual(network, null)))
            {
                Helpers.addElementToObject(request, "network", network);
                parameters = this.omit(parameters, "network");
            }
            // has support for the 'network' parameter
            // https://binance-docs.github.io/apidocs/spot/en/#deposit-address-supporting-network-user_data
            Object response = (this.privateGetOpenV1DepositsAddress(this.extend(request, parameters))).join();
            //
            //     {
            //         "code":0,
            //         "msg":"Success",
            //         "data":{
            //             "uid":"182395",
            //             "asset":"USDT",
            //             "network":"ETH",
            //             "address":"0x101a925704f6ff13295ab8dd7a60988d116aaedf",
            //             "addressTag":"",
            //             "status":1
            //         },
            //         "timestamp":1660685915746
            //     }
            //
            Object data = this.safeValue(response, "data", new java.util.HashMap<String, Object>() {{}});
            Object address = this.safeString(data, "address");
            Object tag = this.safeString(data, "addressTag", "");
            if (Helpers.isTrue(Helpers.isEqual(((String)tag).length(), 0)))
            {
                tag = null;
            }
            this.checkAddress(address);
            final Object finalTag = tag;
            return new java.util.HashMap<String, Object>() {{
                put( "info", response );
                put( "currency", code );
                put( "network", TokocryptoCore.this.safeString(data, "network") );
                put( "address", address );
                put( "tag", finalTag );
            }};
        });

    }

